message.content:
{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires calculating the Rydberg energy (binding energy) for a specific exciton state using the hydrogenic model. The first step is to find the effective Rydberg constant (R*) using the 1s binding energy, and the second step is to scale that constant to the n=3 state.",
  "helpers": [
    {
      "label": "helper_1",
      "instructions": "Calculate the effective Rydberg energy (R*) for this system. The 1s exciton peak is at 1 eV, and the band gap is 3 eV. The binding energy of the 1s state (E_b_1s) is the difference between the band gap and the peak energy. In the hydrogenic model, the binding energy for the 1s state is equal to R*. Extract this value."
    },
    {
      "label": "helper_2",
      "instructions": "Using the effective Rydberg energy (R*) found in the first step, calculate the binding energy for the n = 3 state. Use the hydrogenic formula for energy levels: E_n = R* / (n^2). Calculate the specific value for n = 3. Ensure the result is expressed as the binding energy (the magnitude of the energy below the band edge)."
    }
  ],
  "synthesis_brief": "Subtract the 1s peak energy from the band gap to find the 1s binding energy (R*). Then, divide R* by n squared (where n=3) to find the Rydberg energy for the n=3 state."
}

